-- Draft, industry-standard SOP checklist items for each Job Flow step, generated so there's
-- a starting point to edit rather than an empty list. Content is templated by status name
-- (the same status name means largely the same procedure regardless of subcategory) — go
-- through each one in the Job Flow admin page and adjust to match exactly how Penfix does it.
-- Only inserts where the step doesn't already have any SOP items, so it's safe to re-run.

do $$
begin
  if not exists (select 1 from subcategory_sop_procedures where sop_id = 'ACR-3MM-CLR-01-STEP-1') then
    insert into subcategory_sop_procedures (procedure_id, sop_id, sequence, is_active, instruction) values ('ACR-3MM-CLR-01-STEP-1-PROC-1', 'ACR-3MM-CLR-01-STEP-1', 1, true, 'Confirm order details (item, quantity, size, specs) match what the client requested.');
    insert into subcategory_sop_procedures (procedure_id, sop_id, sequence, is_active, instruction) values ('ACR-3MM-CLR-01-STEP-1-PROC-2', 'ACR-3MM-CLR-01-STEP-1', 2, true, 'Verify payment status meets the required threshold before proceeding.');
    insert into subcategory_sop_procedures (procedure_id, sop_id, sequence, is_active, instruction) values ('ACR-3MM-CLR-01-STEP-1-PROC-3', 'ACR-3MM-CLR-01-STEP-1', 3, true, 'Log the job in the queue with the correct deadline and priority.');
  end if;
end $$;

